import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Contributing","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/index.md","filePath":"contributing/index.md","lastUpdated":1777921494000}'),n={name:"contributing/index.md"};function s(i,e,c,d,l,p){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h1><blockquote><p><strong>Renamed 2026-05-03</strong> — see <a href="./2026-05-03-zkqes-rename-design"><code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code></a> for the rename baseline. Historical references to QKB/QIE/Identity-Escrow in pre-2026-05-03 commits remain immutable in git history.</p></blockquote><p>How V5 amendments get built. The pattern repeats across every phase: spec → orchestration plan → per-worker plans → dispatch.</p><h2 id="worktree-layout" tabindex="-1">Worktree layout <a class="header-anchor" href="#worktree-layout" aria-label="Permalink to &quot;Worktree layout&quot;">​</a></h2><p>The team operates in dedicated worktrees per worker, never sharing CWD. Concretely:</p><ul><li><code>flattener-eng</code> — <code>packages/lotl-flattener</code></li><li><code>circuits-eng</code> — <code>packages/circuits</code></li><li><code>contracts-eng</code> — <code>packages/contracts</code></li><li><code>web-eng</code> — <code>packages/web</code> + <code>packages/sdk</code></li><li><code>qie-eng</code> — <code>packages/qie-{core,agent,cli}</code> (Phase 2)</li></ul><p>Lead operates in the main checkout. See <code>CLAUDE.md</code> at the repo root for the full orchestration playbook.</p><h2 id="plan-driven-execution" tabindex="-1">Plan-driven execution <a class="header-anchor" href="#plan-driven-execution" aria-label="Permalink to &quot;Plan-driven execution&quot;">​</a></h2><p>Every phase has:</p><ul><li>One <strong>design spec</strong> at <code>docs/superpowers/specs/YYYY-MM-DD-&lt;topic&gt;-design.md</code> (brainstorming output).</li><li>One <strong>orchestration plan</strong> at <code>docs/superpowers/plans/YYYY-MM-DD-&lt;topic&gt;-orchestration.md</code> — interface contracts, dispatch order, merge strategy, lead-side scaffold steps.</li><li>One <strong>per-worker plan</strong> at <code>docs/superpowers/plans/YYYY-MM-DD-&lt;topic&gt;-&lt;worker&gt;.md</code> — bite-sized TDD tasks, exact file paths, complete code.</li></ul><p>Interface contracts in the orchestration plan are <strong>frozen early</strong>. Changes require explicit lead sign-off and a cross-worker broadcast.</p><h2 id="recent-orchestration-plans" tabindex="-1">Recent orchestration plans <a class="header-anchor" href="#recent-orchestration-plans" aria-label="Permalink to &quot;Recent orchestration plans&quot;">​</a></h2><p>The plans tree is comprehensive but not curated; consult these as patterns when shipping a new amendment:</p><ul><li>V5 architecture (Phase 1 baseline)</li><li>V5.1 wallet-bound nullifier amendment</li><li>V5.2 keccak-on-chain amendment</li><li>V5.3 OID-anchor amendment (in flight at time of writing)</li><li>V5.4 zkqes CLI-server (zkqes serve)</li></ul><p>Each amendment ships in 3-7 days end-to-end across spec → plan → dispatch → ceremony. The cadence is preserved by codex VERDICT in every commit footer + per-task verification gates.</p><h2 id="coding-standards" tabindex="-1">Coding standards <a class="header-anchor" href="#coding-standards" aria-label="Permalink to &quot;Coding standards&quot;">​</a></h2><p>See <code>packages/&lt;package&gt;/CLAUDE.md</code> for package-specific invariants. The web package&#39;s CLAUDE.md (V5.16-V5.21 invariants) captures most cross-cutting rules.</p><p>Footer policy:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VERDICT: PASS (manual review; SKIP_CODEX_REVIEW=1 per worker</span></span>
<span class="line"><span>guidance — codex daemon corrupts git index).</span></span></code></pre></div><p>every commit. No exceptions.</p><h2 id="where-to-start" tabindex="-1">Where to start <a class="header-anchor" href="#where-to-start" aria-label="Permalink to &quot;Where to start&quot;">​</a></h2><p>If you want to ship a single contained change: pick a <a href="https://github.com/alik-eth/zkqes/issues" target="_blank" rel="noreferrer">pending task</a> marked <code>good first contribution</code> and follow the per-worker dispatch pattern.</p><p>If you want to ship an amendment: read <a href="/specs/v5-architecture">V5 architecture</a> end-to-end, then propose a spec via PR. Lead reviews, founder approves, dispatch follows.</p>`,23)])])}const g=a(n,[["render",s]]);export{u as __pageData,g as default};
